import{_ as t,o as r,c as n,j as e,a as p,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const b=JSON.parse('{"title":"心愿的便签本","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/0.无支线/心愿的便签本.md","filePath":"4.资源分区/7.物品与装备/4.奇物/0.无支线/心愿的便签本.md"}'),o={name:"4.资源分区/7.物品与装备/4.奇物/0.无支线/心愿的便签本.md"};function d(_,a,l,i,c,h){return r(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"心愿的便签本",tabindex:"-1"},[p("心愿的便签本 "),e("a",{class:"header-anchor",href:"#心愿的便签本","aria-label":'Permalink to "心愿的便签本"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌030")])])],-1),s('<h1 id="心愿的便签本-1" tabindex="-1">心愿的便签本 <a class="header-anchor" href="#心愿的便签本-1" aria-label="Permalink to &quot;心愿的便签本&quot;">​</a></h1><p>心愿的便签本 10分</p><p>特异本质</p><p>这只是一本普普通通的便签本，甚至似乎有些旧的样子。嗯，很贵吗？那，一、二、三，呼——那它现在是一本被祝福过的便签本啦！</p><p>这本便签本的纸张在记录东西时可以看作是无限的，颜色款式随心情变换。虽然也能当普通便签用，但它通常可以用来记录更重要的事。影片内达成的约定，立下的誓言，都可以被记录在上面。当约定被大家确认，将这页便签撕下后，所有愿意记住这个约定的人，都将会同样地获得这张便签。</p><p>被留下誓言的便签，纸张将会变得异常坚韧，文字也无法被磨灭或涂改，它会为了那个约定，一直保持在记录下的那一刻。对于对于轮回者来说，这张标签，连同上面的誓言都可以被记录在自己的获得物品中，这不会带来其他的好处，但它会被你以这种形式永久地记录下来，哪怕直到从主神空间毕业的那一刻。</p><p>嗯，不过这样有什么意义呢？大概只是因为大家都是很健忘的吧，既然如此，就让那些不想被遗忘的东西以这种方式留下印记。无论那之后的日子如何，也无论它是否曾经被实现过，只是被记录下的那一刻本身就已经值得纪念。</p><p>就当，给杂乱的生活添加一点小小的仪式感好了？</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',10)])])}const m=t(o,[["render",d]]);export{b as __pageData,m as default};
